VALUES
  ('dietitian-moex-01023', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於ATP的敘述，下列何者正確？', '["含有3個高能磷酸鍵", "用來驅動吸熱反應（endergonicreaction）", "用來維持體溫", "在生熱素（thermogeninorUCP1）存在下由ATPsynthase合成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01024', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'essay', '劉先生，30 歲，身高 180 公分，體重 70 公斤，無抽菸及喝酒習慣，無
任何慢性疾病也無服用任何藥物。某日因與人發生爭執，腹部遭鈍器多
重刺傷，傷勢嚴重被緊急送往某醫院。劉先生被插上呼吸器，進行胃修
補（gastricrepair）以及切除部分的近端空腸，之後送往外科加護病房照
護。劉先生於手術後體溫：38C、血壓：135/75mmHg、血糖：170mg/dL、
白蛋白：3.0g/dL、C-反應蛋白（C-reactiveprotein）：20mg/L。目前腹部
仍然腫脹堅硬，無腸音，接受靜脈營養支持，以及每小時20 毫升的異丙
酚（propofol，一種鎮靜藥物）注射。請依劉先生目前的臨床狀況，計算
靜脈營養支持方式所需的熱量及蛋白質。請試述在給予劉先生所需要的
熱量時，是否需要考慮異丙酚的注射量，原因為何？並試述劉先生可以
轉換成腸道營養支持型式的判斷依據，以及可以完全脫離靜脈營養支持
型式的評估標準。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01025', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'essay', '吳先生是某科技公司的工程師，40 歲，身高175公分，平時體重大約 80
公斤，每天喝 3杯加 2匙糖的美式咖啡，喜歡吃油炸食物，經常需要喝
酒應酬，每星期去健身房 3次。去年因健身受傷而接受膝關節手術後幾
乎沒有運動，體重約增加 8公斤。最近經常出現消化不良，且時常感覺
由上腹部往咽喉處有灼熱感，甚至會有胸痛的感覺而就醫，經醫師診斷
為胃食道逆流（gastroesophagealrefluxdisease）。請試述造成吳先生胃食
道逆流的可能原因以及可能產生的併發症，並試述吳先生的飲食及營養
照護建議。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01026', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'essay', '鄭先生，55 歲，末期肝衰竭病人，近日成功接受肝臟移植手術。請試述
鄭先生術後二個月內以及之後的熱量、蛋白質和其餘飲食及營養照護原
則。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01027', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '營養照護程序（nutritioncareprocess,NCP）是一個標準化的、有計畫性的營養照護過程，其包括', '["營養評估", "營養監測與評值", "營養介入", "營養教育   ⑤營養 診斷  ⑥營養諮商"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01028', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '在執行營養照護的過程中，必須提供具有實證的營養施行指南（evidence-based nutrition practice guidelines），這些證據通常來自於不同類型的文獻研究，但不包括下列那一類？', '["隨機對照實驗（randomizedcontrolledtrails）", "系統性文獻回顧（systematicreviews）", "動物性實驗（animalstudy）", "統合性論文（meta-analysis）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01029', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王爺爺因為中風導致左半邊輕癱，吃飯時候常發生嗆咳的情況。身高 165 公分、通常體重 58 公 斤、近一個月減輕為55公斤。家屬製備剁碎飲食、每日四餐，但每日攝食量約一半。針對此個案 以SOAP（Subjective,Objective,Assessment,Plan）格式進行營養病歷書寫時，下列書寫內容何者 錯誤？', '["「吃飯嗆咳情況」應記錄在S", "「身高和體重」應記錄在A", "「中風導致左半邊輕癱」應記錄在O", "「家屬製備剁碎飲食」應記錄在S"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01030', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '選擇營養支持途徑時，腸道營養優於靜脈營養使用原因，下列何者錯誤？', '["腸道營養能維持腸道黏膜的完整性與其屏障功能", "腸道營養能提供較高的熱量", "腸道營養導致的代謝異常比靜脈營養少", "腸道營養較能維護免疫功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01031', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '林先生40歲，體重60公斤，因中風使用鼻胃管灌食，除高血壓外無其他疾病，評估每日熱量 需要30kcal/kg，下列有關灌食敘述何者錯誤？', '["使用標準均衡配方（1kcal/mL）時，每日需要提供1,800mL才能達到熱量需要量", "使用continuousfeeding時，可用全濃度灌食不需要稀釋配方", "灌食配方需有2%至4%的熱量來自MCT（medium-chaintriglycerides）oil才能避免必需脂肪酸 缺乏", "林先生水分的需要量每日約需1,800~2,100mL"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01032', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關腸道營養支持常見併發症的敘述，下列何者正確？', '["常規測量胃殘餘量是避免管灌病患吸入性肺炎最主要的方法", "管灌配方中含有膳食纖維有助於改善長期管灌病人便秘", "加護病房（ICU）病人應常規使用含纖管灌配方，以避免腹瀉", "管灌病患有胃輕癱（gastroparesis）症狀時，可使用制酸劑以增加病患對灌食的耐受性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
